import { readFileSync, existsSync, readdirSync } from "node:fs";
import assert from "node:assert/strict";

const result = JSON.parse(readFileSync("RESULT.json", "utf8"));
assert.equal(result.alpha, "alpha-mega-11");
assert.equal(result.beta, "beta-mega-22");
assert.equal(result.token, "STRESS-TOKEN-991");
const done = readFileSync("DONE.md", "utf8");
assert.match(done, /STRESS-TOKEN-991/);
assert.match(done, /alpha-mega-11/);
assert.match(done, /beta-mega-22/);
const scratch = existsSync(".reaper/memory/scratch.md")
  ? readFileSync(".reaper/memory/scratch.md", "utf8")
  : "";
assert.match(scratch, /STRESS-TOKEN-991/);
const noise = readdirSync("noise").filter((f) => /^n\d{2}\.txt$/.test(f));
assert.ok(noise.length >= 20, `expected >=20 noise files, got ${noise.length}`);
console.log("ok");
